commits.content:
.recruiter-wrapper {
  position: relative;
  display: flex;
  justify-content: end;
}
.recruiter-wrapper::after {
  position: absolute;
  content: "";
  top: 50%;
  transform: translateY(-50%);
  height: 41px;
  border-left: 1px solid var(--black);
  left: 15px;
}
a.al-logo {
  color: #fff;
  display: block;
  font-size: 24px;
  font-family: Roboto,sans-serif;
  white-space: nowrap;
  float: left;
  outline: 0!important;
  line-height: 60px;
  margin-left: 40%;
}
a {
  transition: color .5s ease;
}
a.collapse-menu-link {
  font-size: 31px;
  cursor: pointer;
  display: block;
  text-decoration: none;
  line-height: 42px;
  color: #fff;
  padding: 0;
  float: left;
  margin: 11px 0 0 25px;
}
.header-component {
  height: 100%;
}
.logo-wrapper img {
  width: 160px;
}
.dropdown-component {
  height: 100%;
}

//  .input-text-add, .input-text-job {
//     padding: 10px 10px;
// }

.login-text {
  cursor: pointer;
}
.login-text-wrapper {
  padding: unset;
}
.header-up .left-txt, .header-up .middle-txt, .header-up .right-txt {
  width: 10%;
}
.avatar-wrapper {
  position: relative;
}
.dropdown-wrapper {
  position: absolute;
  top: 100%;
  right: 75%;
  z-index: 999;
}
/* Mobile & tablet */
@media (max-width: 1023px) {
  .hide-on-mobile-tablet {
      display: none;
  }
}

/* Tablet */
@media (min-width: 740px) and (max-width: 1023px) {
  .hide-on-tablet {
      display: none;
  }
}

/* Mobile */
@media (max-width: 739px) {
  .hide-on-mobil {
      display: none;
  }
}

.topnav {
  overflow: hidden;
}

.topnav a {
  float: left;
  display: block;
  text-align: center;
  padding: 14px 16px;
  text-decoration: none;
  font-size: 17px;
}

.topnav a:hover {
  // background-color: #ddd;
}

.topnav a.active {
  // color: #004AAD;
  // color: white;
}

.topnav .icon {
  display: none;
}
.navbar {
  height: 100%;
}
@media screen and (max-width: 600px) {
  .topnav a:not(:first-child) {display: none;}
  .topnav a.icon {
    float: left;
    display: block;
  }
}

@media screen and (max-width: 600px) {
  .topnav.responsive {position: relative;}
  .topnav.responsive .icon {
    position: absolute;
    right: 0;
    top: 0;
  }
  .topnav.responsive a {
    float: none;
    display: block;
    text-align: left;
  }
}
.active-link {
  color: #00b14f;
}
.notification-container {
  max-width: 100%;
  .notification-item {
    padding: 10px;
    border-bottom: 1px solid #e5e7eb;
    &.unread {
      background-color: #e6f3ff;
      font-weight: bold;
    }
    &:last-child {
      border-bottom: none;
    }
  }
}

.relative {
  position: relative;
}

.absolute {
  position: absolute;
}

/* Style cho badge */
.bg-red-600 {
  background-color: #dc2626;
}

.text-white {
  color: #ffffff;
}

.rounded-full {
  border-radius: 9999px;
}

.max-h-96 {
  max-height: 24rem;
}

.overflow-y-auto {
  overflow-y: auto;
}
